  function buildLearnPrompts(groups) {
    return Object.entries(groups).flatMap(([learnTopic, prompts]) => {
      return prompts.map(([id, text]) => ({
        id,
        category: 'learn',
        learnTopic,
        ageGroups: ['*'],
        regions: ['*'],
        requiresTimer: false,
        text,
        points: 1,
      }));
    });
  }

  const learningPrompts = buildLearnPrompts(learnPromptGroups);

